Plan for `macos/Lex.swift`:

1. Retain signal sources on `AppDelegate`
2. Install signal handling during app launch
3. Convert handled signals into normal AppKit termination
4. Keep cleanup in `applicationWillTerminate(_:)`

Example code:

```swift
final class AppDelegate: NSObject, NSApplicationDelegate {
    @MainActor
    let appState = AppState()

    private var engineState: UnsafeMutableRawPointer?
    private var signalSources: [DispatchSourceSignal] = []

    func applicationDidFinishLaunching(_ notification: Notification) {
        print("Activated.")
        installSignalHandlers()
        initializeEngineState()
        // Start event tap.
    }

    func applicationWillTerminate(_ notification: Notification) {
        print("Shutting down...")
        // Stop event tap.
        destroyEngineState()
        signalSources.removeAll()
    }

    private func installSignalHandlers() {
        installSignalHandler(SIGINT)
        installSignalHandler(SIGTERM)
    }

    private func installSignalHandler(_ signalNumber: Int32) {
        signal(signalNumber, SIG_IGN)

        let source = DispatchSource.makeSignalSource(
            signal: signalNumber,
            queue: .main
        )

        source.setEventHandler {
            NSApp.terminate(nil)
        }

        source.resume()
        signalSources.append(source)
    }

    private func initializeEngineState() {
        precondition(engineState == nil)
        let byteCount = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)
        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byteCount,
            alignment: alignment
        )
        lex_state_init(state)
        engineState = state
    }

    private func destroyEngineState() {
        guard let state = engineState else {
            return
        }
        state.deallocate()
        engineState = nil
    }
}
```

Notes:

- `signal(signalNumber, SIG_IGN)` is required so the default POSIX action does not kill the process before the dispatch source runs.
- `DispatchSourceSignal` must be retained. If it is a local variable only, it can be deallocated and stop working.
- `NSApp.terminate(nil)` routes interruption through AppKit, so `applicationWillTerminate(_:)` still owns cleanup.
- `SIGINT` covers `Ctrl+C`.
- `SIGTERM` covers normal external termination such as `kill <pid>`.
- Do not call Swift/AppKit cleanup directly from a POSIX signal handler. The dispatch source handler on `.main` is the safe bridge.
